// OrderCartContext.js
import { useState, createContext, useContext } from "react";

const OrderContext = createContext();

export const OrderProvider = ({ children }) => {
  const [order, setOrder] = useState({});
  const [menu, setMenu] = useState([]);

  const addToOrder = (productID, quantity) => {
    setOrder(prevOrder => {
      // Get current item quantity
      const currentQuantity = prevOrder[productID]?.quantity || 0;
      const newQuantity = currentQuantity + quantity;

      // If quantity becomes 0 or negative, remove item
      if (newQuantity <= 0) {
        const { [productID]: removed, ...rest } = prevOrder;
        return rest;
      }

      // Update or add item
      return {
        ...prevOrder,
        [productID]: {
          ...prevOrder[productID],
          quantity: newQuantity,
          price: prevOrder[productID]?.price || 0,
          description: prevOrder[productID]?.description || ''
        }
      };
    });
  };

  const setInitialProductDetails = (name, price, description) => {
    setOrder(prevOrder => ({
      ...prevOrder,
      [name]: {
        ...prevOrder[name],
        price,
        description,
        quantity: prevOrder[name]?.quantity || 0
      }
    }));
  };

  const removeFromOrder = (productID) => {
    setOrder(prevOrder => {
      const { [productID]: removed, ...rest } = prevOrder;
      return rest;
    });
  };

  return (
    <OrderContext.Provider value={{ 
      order, 
      addToOrder,
      removeFromOrder,
      menu, 
      setMenu,
      setInitialProductDetails
    }}>
      {children}
    </OrderContext.Provider>
  );
};

export const useOrderContext = () => useContext(OrderContext);
